USERS = ("farms", "city", "industry")

def transition(state, action):
    s = dict(state)
    # actions arrive as {"name": ..., "params": {...}} (params absent in previews)
    if isinstance(action, dict):
        name = action.get("name")
        params = action.get("params") or {}
    else:
        name, params = action, {}

    if name == "release":
        rf = float(s.get("ration_factor", 1.0))
        desired = {u: float(s["alloc_" + u]) * rf for u in USERS}
        total = sum(desired.values())
        avail = float(s["reservoir"])
        if total <= avail or total <= 0:
            scale, s["shortfall"] = 1.0, 0.0
        else:
            scale = avail / total
            s["shortfall"] = round(total - avail, 3)
        delivered = 0.0
        for u in USERS:
            d = desired[u] * scale
            s["recv_" + u] = round(float(s["recv_" + u]) + d, 3)
            delivered += d
        s["reservoir"] = round(avail - delivered, 3)
        s["cycle"] = int(s.get("cycle", 0)) + 1

    elif name == "ration":
        factor = float(params.get("factor", 0.5))
        s["ration_factor"] = max(0.0, min(1.0, factor))

    elif name == "refill":
        amount = float(params.get("amount", s.get("inflow", 0.0)))
        amount = max(0.0, amount)
        s["reservoir"] = round(min(float(s["capacity"]),
                                   float(s["reservoir"]) + amount), 3)

    return s

