def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k, v = k.strip().lower(), v.strip()
        if k in ('inflow', 'forecast'):
            try:
                out['inflow'] = max(0.0, float(v))
            except ValueError:
                pass
    return out
